fn is_git_repo(&self) -> bool {
        // Walk up from data_dir looking for .git
        let mut dir = self.data_dir.as_path();
        loop {
            if dir.join(".git").exists() {
                return true;
            }
            match dir.parent() {
                Some(parent) => dir = parent,
                None => return false,
            }
        }
    }
